#!/bin/bash
# DSL pour générer des configs nginx

# Variables d'état du DSL
declare -a SERVERS
declare -A SERVER_CONFIG

# Fonctions DSL
server() {
    local name=$1
    SERVERS+=("$name")
    _current_server="$name"
}

listen() { SERVER_CONFIG["$_current_server.listen"]=$1; }
root()   { SERVER_CONFIG["$_current_server.root"]=$1; }
index()  { SERVER_CONFIG["$_current_server.index"]=$1; }

# Générateur nginx
generate_nginx() {
    for srv in "${SERVERS[@]}"; do
        local port=${SERVER_CONFIG["$srv.listen"]:-80}
        local root=${SERVER_CONFIG["$srv.root"]:-/var/www/html}
        local idx=${SERVER_CONFIG["$srv.index"]:-index.html}

        cat << EOF
server {
    listen $port;
    server_name $srv;
    root $root;
    index $idx;
}

EOF
    done
}

# Utilisation du DSL
server "example.com"
    listen 80
    root /var/www/example
    index index.html

server "api.example.com"
    listen 8080
    root /var/www/api

generate_nginx
```

