#!/bin/bash
# Mini interpréteur de commandes personnalisées

declare -A VARIABLES

eval_expr() {
    local expr=$1
    # Substituer les variables
    while [[ $expr =~ \$([A-Za-z_][A-Za-z0-9_]*) ]]; do
        local var=${BASH_REMATCH[1]}
        local val=${VARIABLES[$var]:-}
        expr=${expr/\$$var/$val}
    done
    # Évaluer l'expression arithmétique
    echo $((expr))
}

execute_command() {
    local cmd=$1 args=${@:2}

    case "$cmd" in
        set)
            local var val
            IFS='=' read -r var val <<< "$args"
            VARIABLES[$var]=$val
            echo "$var = $val"
            ;;
        print)
            local val=${args/\$/${VARIABLES[}  # simplification
            echo "${args//\$([A-Za-z_]*)/${VARIABLES[\1]:-}}"  
            ;;
        calc)
            echo "= $(eval_expr "$args")"
            ;;
        quit) exit 0 ;;
        help) echo "Commandes : set var=val | print expr | calc expr | quit" ;;
        *) echo "Commande inconnue : $cmd" >&2 ;;
    esac
}

# Lire depuis stdin ou fichier
while IFS= read -r line; do
    [[ $line =~ ^[[:space:]]*$ || $line =~ ^# ]] && continue
    execute_command $line
done
